al_id,\\r\\n                        lastDocument.document_type_id\\r\\n                    )\\r\\n                \\\">\\r\\n                    <i class=\\\"fas fa-print\\\"></i>\\r\\n                </el-button>\\r\\n            </div>\\r\\n            <div>\\r\\n                <el-tabs v-model=\\\"activeName\\\" @tab-click=\\\"handleClick\\\">\\r\\n                    <el-tab-pane label=\\\"Notas de venta\\\" name=\\\"saleNotes\\\">\\r\\n                        <document-print-detail :company=\\\"company\\\" @getRecords=\\\"getRecords\\\" @printData=\\\"printData\\\"\\r\\n                            :records.sync=\\\"saleNotes\\\" :pagination.sync=\\\"pagination.saleNotes\\\" :type=\\\"'saleNotes'\\\"\\r\\n                            :sender=\\\"sender\\\">\\r\\n                        </document-print-detail>\\r\\n                    </el-tab-pane>\\r\\n                    <el-tab-pane v-if=\\\"company.soap_type_id != '03'\\\" label=\\\"Facturas - Boletas\\\" name=\\\"documents\\\">\\r\\n                        <document-print-detail :sender=\\\"sender\\\" :company=\\\"company\\\" @getRecords=\\\"getRecords\\\"\\r\\n                            @printData=\\\"printData\\\" :records.sync=\\\"documents\\\" :pagination.sync=\\\"pagination.documents\\\"\\r\\n                            :type=\\\"'documents'\\\">\\r\\n                        </document-print-detail>\\r\\n                    </el-tab-pane>\\r\\n                </el-tabs>\\r\\n            </div>\\r\\n        </div>\\r\\n    </el-dialog>\\r\\n</template>\\r\\n<style>\\r\\n    .el-dialog__header {\\r\\n        background-color: var(--primary) !important; \\r\\n    }\\r\\n    .el-dialog__title {\\r\\n        color: var(--light-text) !important;\\r\\n    }\\r\\n    .el-dialog__headerbtn .el-dialog__close{\\r\\n        color:white !important;\\r\\n    }\\r\\n</style>\\r\\n<script>\\r\\nimport DocumentPrintDetail from \\\"./document_print_detail.vue\\\";\\r\\nimport queryString from \\\"query-string\\\";\\r\\nexport default {\\r\\n    components: { DocumentPrintDetail },\\r\\n    props: [\\\"showDialog\\\", \\\"company\\\", \\\"sender\\\",\\\"config\\\", \\\"establishment\\\"],\\r\\n    data() {\\r\\n        return {\\r\\n            time: null,\\r\\n            loading: false,\\r\\n            value: null,\\r\\n            typeSearch: \\\"document\\\",\\r\\n            saleNotes: [],\\r\\n            documents: [],\\r\\n            pagination: {\\r\\n                saleNotes: {},\\r\\n                documents: {}\\r\\n            },\\r\\n            printer: null,\\r\\n            lastDocument: null,\\r\\n            activeName: \\\"documents\\\"\\r\\n        };\\r\\n    },\\r\\n    methods: {\\r\\n        getRecordsInput() {\\r\\n            this.getRecords();\\r\\n        },\\r\\n        async printEvent(url) {\\r\\n            \\r\\n            let paperConfig = {\\r\\n                scaleContent: false     \\r\\n            };\\r\\n            let partsUrl = url.split(\\\"/\\\");\\r\\n            let document = partsUrl[partsUrl.length - 1];\\r\\n            let isTicket = document.toLowerCase().includes(\\\"ticket\\\")\\r\\n           \\r\\n            let tipoBandejaImpresora = this.config.new_old_printer;\\r\\n\\r\\n            if (!isTicket && tipoBandejaImpresora == 1) {//opciones que permiten hacer una impresion correcta en impresoras nuevas\\r\\n                paperConfig.density = 600 ;\\r\\n                paperConfig.orientation= 'portrait';\\r\\n                paperConfig.margins = {left: 2}\\r\\n                }else if(!isTicket && tipoBandejaImpresora == 0){\\r\\n                paperConfig.density = 350 ;\\r\\n                paperConfig.orientation= 'portrait';\\r\\n                \\r\\n            }\\r\\n\\r\\n            try {\\r\\n                let config = qz.configs.create(this.printer, paperConfig);\\r\\n                if (!qz.websocket.isActive()) {\\r\\n                    await qz.websocket.connect(config);\\r\\n                }\\r\\n                let data = [\\r\\n                    {\\r\\n                        type: \\\"pdf\\\",\\r\\n                        format: \\\"file\\\",\\r\\n                        data: url\\r\\n                    }\\r\\n                ];\\r\\n                qz.print(config, data).catch(e => {\\r\\n                    this.$toast.error(e.message);\\r\\n                });\\r\\n            } catch (e) { }\\r\\n        },\\r\\n        async printData(external_id, type) {\\r\\n            let typePrint = this.establishment.format_printer\\r\\n            let url = \\\"\\\";\\r\\n            //colocar una condicion para cada caso desde impresira de 80mm hasta las a4 y a5\\r\\n            if(typePrint == '1'){//tamaño a4\\r\\n                if (type == \\\"80\\\") {\\r\\n                    url = `/sale-notes/print/${external_id}/a4`;\\r\\n                } else {\\r\\n                    url = `/print/document/${external_id}/a4`;\\r\\n                }\\r\\n            }\\r\\n            if(typePrint == '2'){//tamaño a5\\r\\n                if (type == \\\"80\\\") {\\r\\n                    url = `/sale-notes/print/${external_id}/a5`;\\r\\n                } else {\\r\\n                    url = `/print/document/${external_id}/a5`;\\r\\n                }\\r\\n            }   \\r\\n            if(typePrint == '3'){//tamaño 80mm\\r\\n                if (type == \\\"80\\\") {\\r\\n                    url = `/sale-notes/print/${external_id}/ticket`;\\r\\n                } else {\\r\\n                    url = `/print/document/${external_id}/ticket`;\\r\\n                }\\r\\n            }\\r\\n            if(typePrint == '4'){//tamaño 50mm\\r\\n                if (type == \\\"80\\\") {\\r\\n                    url = `/sale-notes/print/${external_id}/ticket_50`;\\r\\n                } else {\\r\\n                    url = `/print/document/${external_id}/ticket_50`;\\r\\n                }\\r\\n            }\\r\\n\\r\\n            await this.printEvent(url);\\r\\n        },\\r\\n        async getLastDocument() {\\r\\n            try {\\r\\n                this.loading = true;\\r\\n                const response = await this.$http(`print_last_document`);\\r\\n\\r\\n                if (response.status == 200) {\\r\\n                    const {\\r\\n                        data: { document }\\r\\n                    } = response;\\r\\n                    this.lastDocument = document;\\r\\n                    let filename = this.lastDocument.filename.split(\\\"-\\\");\\r\\n                    this.lastDocument.numberPrint =\\r\\n                        filename[2] + \\\"-\\\" + filename[3];\\r\\n                }\\r\\n            } catch (e) {\\r\\n                this.$toast.error(\\\"No se pudo obtener el ultimo documento\\\");\\r\\n            } finally {\\r\\n                this.loading = false;\\r\\n            }\\r\\n        },\\r\\n        async getPrinter() {\\r\\n            const response = await this.$http(\\r\\n                `cash/get_printer/${this.area_id}`\\r\\n            );\\r\\n\\r\\n            let {\\r\\n                data: { printer }\\r\\n            } = response;\\r\\n            this.printer = printer;\\r\\n        },\\r\\n        getRecords(page = 1) {\\r\\n            if (this.activeName == \\\"saleNotes\\\") {\\r\\n                this.pagination.saleNotes.current_page = Number(page);\\r\\n            } else {\\r\\n                this.pagination.documents.current_page = Number(page);\\r\\n            }\\r\\n            if (this.time) {\\r\\n                clearTimeout(this.time);\\r\\n            }\\r\\n            this.time = setTimeout(async () => {\\r\\n                await this.getLastDocuments();\\r\\n            }, 500);\\r\\n        },\\r\\n        getQueryParameters(form = {}) {\\r\\n            let page =\\r\\n                this.activeName == \\\"saleNotes\\\"\\r\\n                    ? this.pagination.saleNotes.current_page\\r\\n                    : this.pagination.documents.current_page;\\r\\n            return queryString.stringify({\\r\\n                page:\\r\\n                    this.activeName == \\\"saleNotes\\\"\\r\\n                        ? this.pagination.saleNotes.current_page\\r\\n                        : this.pagination.documents.current_page,\\r\\n                isNote: this.activeName == \\\"saleNotes\\\",\\r\\n                column: this.typeSearch,\\r\\n                value: this.value\\r\\n\\r\\n                // limit: this.limit\\r\\n            });\\r\\n        },\\r\\n        handleClick() {\\r\\n            if (this.saleNotes.length == 0 || this.documents.length == 0) {\\r\\n                this.getLastDocuments();\\r\\n            }\\r\\n        },\\r\\n        async open() {\\r\\n            await this.getLastDocument();\\r\\n            await this.getLastDocuments();\\r\\n            await this.getPrinter();\\r\\n        },\\r\\n        close() {\\r\\n            this.$emit(\\\"update:showDialog\\\", false);\\r\\n        },\\r\\n\\r\\n        async getLastDocuments() {\\r\\n            //\\\"/sale-notes/print/{$doc->external_id}/ticket\\r\\n            //\\\"/print/document/{$doc->external_id}/ticket\\\";\\r\\n\\r\\n            try {\\r\\n                this.loading = true;\\r\\n                const response = await this.$http(\\r\\n                    `cash/get_last_documents?${this.getQueryParameters()}`\\r\\n                );\\r\\n\\r\\n                if (response.status != 200) {\\r\\n                    this.$toast.error(\\\"No se pudo imprimir\\\");\\r\\n                } else {\\r\\n                    const { data, meta } = response.data;\\r\\n                    if (this.activeName == \\\"saleNotes\\\") {\\r\\n                        this.saleNotes = data;\\r\\n                        this.pagination.saleNotes = meta;\\r\\n                    } else {\\r\\n                        this.documents = data;\\r\\n                        this.pagination.documents = meta;\\r\\n                    }\\r\\n                }\\r\\n            } catch (e) {\\r\\n                console.log(e);\\r\\n                this.$toast.error(\\\"No se pudo imprimir\\\");\\r\\n            } finally {\\r\\n                this.loading = false;\\r\\n            }\\r\\n        }\\r\\n    }\\r\\n};\\r\\n</script>\\r\\n\"],\"sourceRoot\":\"\"}]);\n\n// exports\n\n\n\n//////////////////\n// WEBPACK FOOTER\n// ./node_modules/css-loader?sourceMap!./node_modules/vue-loader/lib/style-compiler?{\"vue\":true,\"id\":\"data-v-c9ff31dc\",\"scoped\":false,\"hasInlineConfig\":true}!./node_modules/vue-loader/lib/selector.js?type=styles&index=0!./modules/Internet/Resources/assets/js/view/pos/partials/documents_print.vue\n// module id = ./node_modules/css-loader/index.js?sourceMap!./node_modules/vue-loader/lib/style-compiler/index.js?{\"vue\":true,\"id\":\"data-v-c9ff31dc\",\"scoped\":false,\"hasInlineConfig\":true}!./node_modules/vue-loader/lib/selector.js?type=styles&index=0!./modules/Internet/Resources/assets/js/view/pos/partials/documents_print.vue\n// module chunks = 57","var render = function() {\n  var _vm = this\n  var _h = _vm.$createElement\n  var _c = _vm._self._c || _h\n  return _c(\n    \"el-dialog\",\n    {\n      directives: [\n        {\n          name: \"loading\",\n          rawName: \"v-loading\",\n          value: _vm.loading,\n          expression: \"loading\"\n        }\n      ],\n      attrs: {\n        \"append-to-body\": \"\",\n        title: \"Enviar documento por whatsapp\",\n        width: \"40%\",\n        visible: _vm.showDialog\n      }\n    },\n    [\n      _c(\"div\", { staticClass: \"card \" }, [\n        _c(\"div\", { staticClass: \"row d-flex align-items-center\" }, [\n          _c(\n            \"div\",\n            { staticClass: \"col-8\" },\n            [\n              _c(\"el-input\", {\n                attrs: { placeholder: \"tlf: 999999999\" },\n                model: {\n                  value: _vm.number,\n                  callback: function($$v) {\n   